{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform managing shipment lifecycle from creation through transit to delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A parcel delivery unit tracking the movement of goods from a pickup address to a delivery address through a defined lifecycle." },
      { "term": "Pickup Address", "definition": "The origin location where goods are collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where goods are delivered to the recipient." },
      { "term": "Shipment State", "definition": "The current lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered." },
      { "term": "Weight Bracket", "definition": "A classification tier determined by shipment weight that governs pricing: Standard (0–10 kg), Heavy (10–50 kg), Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — there is no origin to collect from or destination to deliver to. Data integrity is corrupted if either is missing.",
      "testable_assertion": "Any attempt to create a shipment with a null or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "A shipment in the In Transit state cannot transition back to Pending.",
      "invariant": true,
      "invariant_justification": "This encodes physical reality and state integrity: once goods are physically moving, the system cannot pretend they haven't been picked up. Allowing regression corrupts audit trails and operational truth.",
      "testable_assertion": "Calling any state-change operation on an In Transit shipment that would set its state to Pending must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "A Delivered shipment is in a terminal state — no further state transitions are allowed.",
      "invariant": true,
      "invariant_justification": "Delivery is a finalized real-world event. Reversing it would corrupt fulfillment records, billing, and chain-of-custody integrity. Returns are a separate domain process (e.g., a new reverse shipment).",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment (to Pending, In Transit, or any other state) must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly positive (greater than zero).",
      "invariant": true,
      "invariant_justification": "A shipment with zero or negative weight is physically impossible and would corrupt weight-based pricing calculations.",
      "testable_assertion": "Creating or updating a shipment with weight <= 0 must be rejected."
    },
    {
      "id": "BR-5",
      "rule": "Shipment weight must not exceed 1000 kg.",
      "invariant": false,
      "invariant_justification": "The 1000 kg cap is a business policy reflecting current fleet and infrastructure limits. A VP could raise this to 2000 kg if the company acquires larger vehicles or partners with a freight carrier.",
      "testable_assertion": "Creating or updating a shipment with weight > 1000 kg must be rejected."
    },
    {
      "id": "BR-6",
      "rule": "Weight bracket classification: Standard = weight > 0 and <= 10 kg; Heavy = weight > 10 and <= 50 kg; Freight = weight > 50 and <= 1000 kg.",
      "invariant": false,
      "invariant_justification": "Bracket boundaries are pricing policy. Management can adjust thresholds (e.g., move Heavy to 5–30 kg) without corrupting system state.",
      "testable_assertion": "A shipment of 10 kg must be classified as Standard; 10.01 kg as Heavy; 50 kg as Heavy; 50.01 kg as Freight."
    },
    {
      "id": "BR-7",
      "rule": "The only valid shipment state transitions are: Pending → In Transit, In Transit → Delivered.",
      "invariant": true,
      "invariant_justification": "This is the directed lifecycle graph. Skipping states (Pending → Delivered) or reversing them violates operational reality — goods must be picked up before they can be delivered. Allowing invalid transitions corrupts shipment tracking.",
      "testable_assertion": "A Pending shipment cannot transition directly to Delivered. An In Transit shipment can only transition to Delivered."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A request to create a shipment with a valid pickup address and a valid delivery address and a weight of 5 kg",
      "when": "The shipment is created",
      "then": "The shipment is persisted in Pending state with weight bracket Standard"
    },
    {
      "id": "AC-2",
      "given": "A request to create a shipment missing a pickup address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A request to create a shipment missing a delivery address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "The shipment is transitioned to In Transit",
      "then": "The shipment state becomes In Transit"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "An attempt is made to transition it back to Pending",
      "then": "The system rejects the transition with an error indicating the state change is not allowed"
    },
    {
      "id": "AC-6",
      "given": "A shipment in Delivered state",
      "when": "Any state change is attempted",
      "then": "The system rejects the transition with an error indicating Delivered is a terminal state"
    },
    {
      "id": "AC-7",
      "given": "A request to create a shipment with weight 0 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-8",
      "given": "A request to create a shipment with weight -5 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A request to create a shipment with weight 1001 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight cannot exceed 1000 kg"
    },
    {
      "id": "AC-10",
      "given": "A shipment with weight 10 kg",
      "when": "The weight bracket is determined",
      "then": "The bracket is classified as Standard"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight 25 kg",
      "when": "The weight bracket is determined",
      "then": "The bracket is classified as Heavy"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight 75 kg",
      "when": "The weight bracket is determined",
      "then": "The bracket is classified as Freight"
    },
    {
      "id": "AC-13",
      "given": "A shipment in Pending state",
      "when": "An attempt is made to transition it directly to Delivered",
      "then": "The system rejects the transition — shipments must pass through In Transit before Delivered"
    },
    {
      "id": "AC-14",
      "given": "A shipment in In Transit state",
      "when": "The shipment is transitioned to Delivered",
      "then": "The shipment state becomes Delivered and no further transitions are accepted"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight at exact boundary: 10.0 kg", "expected_behavior": "Classified as Standard (the bracket is 0–10 inclusive). Must be deterministic — never flicker between brackets." },
    { "scenario": "Weight at exact boundary: 50.0 kg", "expected_behavior": "Classified as Heavy (the bracket is 10–50 inclusive)." },
    { "scenario": "Weight at exact boundary: 1000.0 kg", "expected_behavior": "Accepted and classified as Freight. This is the maximum allowed weight." },
    { "scenario": "Weight of 1000.0001 kg (floating point near boundary)", "expected_behavior": "Rejected. Must exceed-check after rounding to avoid floating-point errors letting overweight shipments through." },
    { "scenario": "Duplicate state transition: In Transit → In Transit", "expected_behavior": "Spec is silent. Recommend idempotent acceptance (no-op) since the shipment is already in the target state." },
    { "scenario": "Pickup address and delivery address are identical", "expected_behavior": "Spec is silent. This is physically valid (intra-building delivery) but should be flagged as a warning — likely a user input error." },
    { "scenario": "Concurrent state transitions on the same shipment", "expected_behavior": "Only one transition should succeed. The system must enforce optimistic locking or equivalent to prevent a Delivered shipment from being acted on by a stale In Transit transition." },
    { "scenario": "Shipment weight is extremely small (e.g., 0.001 kg)", "expected_behavior": "Accepted — weight is positive. Classified as Standard." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives pricing. Incorrect bracket assignment means revenue leakage (undercharging Heavy as Standard) or customer disputes (overcharging Standard as Heavy). The 1000 kg cap defines the serviceable market — raising it opens freight revenue opportunities.",
    "operational": "State machine enforcement prevents operational chaos: dispatchers rely on state accuracy to allocate drivers and vehicles. Allowing state regression would corrupt route planning and capacity forecasting.",
    "user": "Clear shipment lifecycle gives senders and recipients reliable tracking. Rejected invalid inputs at creation time prevents frustration downstream (e.g., a shipment stuck with no delivery address).",
    "risk": "Primary risk is bracket boundary bugs causing systematic mispricing. Secondary risk is state machine bypass allowing Delivered shipments to re-enter transit, corrupting fulfillment records and potentially triggering duplicate deliveries or erroneous refunds.",
    "stakeholders_affected": [
      { "group": "Senders (shippers)", "impact": "Pricing accuracy and shipment lifecycle transparency. Incorrect brackets erode trust." },
      { "group": "Recipients", "impact": "Delivery reliability — state integrity ensures accurate tracking and prevents phantom re-deliveries." },
      { "group": "Dispatchers / Operations", "impact": "State machine correctness is foundational to route planning, vehicle allocation, and workload management." },
      { "group": "Finance / Billing", "impact": "Weight bracket accuracy directly determines invoice correctness and revenue recognition." },
      { "group": "Customer Support", "impact": "Clear terminal states reduce disputes. Ambiguous states generate tickets." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec clearly defines the state machine, weight constraints, and bracket boundaries. However, several domain-relevant details are unspecified: the allowed transitions are partially implied (explicit about backward transitions being blocked, but silent on whether Pending→Delivered is allowed — I inferred it is not based on logistics domain knowledge). Boundary inclusivity for brackets (is 10 kg Standard or Heavy?) required interpretation. Address validation depth is unspecified.",
    "high_confidence_areas": [
      "State machine: Pending → In Transit → Delivered is a one-way progression",
      "Delivered is a terminal state — no transitions out",
      "Weight must be positive and <= 1000 kg",
      "Three weight brackets exist with stated boundaries"
    ],
    "low_confidence_areas": [
      "Bracket boundary inclusivity: spec says '0-10' and '10-50' — the 10 kg boundary overlaps textually. I assumed upper-inclusive (10 kg = Standard, 50 kg = Heavy) but this needs PM confirmation.",
      "Whether Pending → Delivered (skipping In Transit) is allowed — spec only explicitly forbids In Transit → Pending and transitions from Delivered. I inferred Pending → Delivered is invalid based on domain reality.",
      "Address validation requirements beyond 'exists' — format, geocoding, serviceability are unspecified.",
      "Whether weight can be modified after shipment creation, and if so, in which states."
    ],
    "assumptions": [
      "Bracket boundaries are upper-inclusive: Standard includes exactly 10 kg, Heavy includes exactly 50 kg.",
      "Pending → Delivered is not a valid transition; shipments must pass through In Transit.",
      "Idempotent same-state transitions (e.g., In Transit → In Transit) are acceptable as no-ops.",
      "Weight is set at creation and the spec does not address mid-lifecycle weight changes.",
      "Returns or reverse logistics are handled as separate shipments, not state reversals."
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Weight bracket boundary overlap: the spec states '0-10 kg is standard, 10-50 kg is heavy.' A shipment weighing exactly 10 kg matches both descriptions. Which bracket owns the boundary value?",
      "affected_stakeholders": ["Finance / Billing", "Senders (shippers)"],
      "options": ["10 kg belongs to Standard (upper-inclusive for lower bracket)", "10 kg belongs to Heavy (lower-inclusive for upper bracket)"],
      "recommendation": "10 kg belongs to Standard (upper-inclusive). This is the more customer-friendly interpretation and aligns with common industry practice where the lower/cheaper tier wins at the boundary."
    },
    {
      "type": "ambiguity",
      "description": "The spec explicitly forbids In Transit → Pending and any transition from Delivered, but is silent on Pending → Delivered. Is skipping In Transit allowed?",
      "affected_stakeholders": ["Dispatchers / Operations", "Recipients"],
      "options": ["Allow Pending → Delivered for edge cases like in-store pickup", "Forbid it — all shipments must transit through In Transit"],
      "recommendation": "Forbid Pending → Delivered. In a courier/logistics domain, a parcel physically must be picked up (entering transit) before it can be delivered. Skipping In Transit misrepresents operational reality. If in-store pickup is needed, model it as a separate flow."
    }
  ],

  "rejection_reasons": []
}

